/* mapper.member.com.erns.coching.MemberDAO.update */

UPDATE T_MEMB_INF SET
	MEMB_NAME = 		#{membName	, jdbcType=VARCHAR}
	, NICKNAME = 		#{nickname	, jdbcType=VARCHAR}
	, PHONE = 			#{phone		, jdbcType=VARCHAR}
	, EMAIL = 			#{email		, jdbcType=VARCHAR}

	, CHNR = 			#{membSeq		, jdbcType=INTEGER}
	, CHNG_DTTM = 		now()

	AND MEMB_SEQ = #{membSeq, jdbcType=INTEGER}

