/* mapper.member.com.erns.coching.MemberDAO.loadMyInfo */
SELECT AA.MEMB_SEQ , AA.MEMB_ID , AA.MEMB_TYPE , AA.PTN_SEQ , AA.MEMB_NAME , AA.NICKNAME , AA.PHONE , AA.EMAIL , AA.RGTR , AA.RGT_DTTM , BB.PTN_SEQ , BB.PTN_NAME , BB.PTN_LIC , BB.PAGE_URL , BB.NATION_NAME , BB.YT_URL , BB.PTN_INTRO , CC.FILE_ID AS PROFILE_ID FROM T_MEMB_INF AA left outer join T_PARTNER_INF BB ON AA.PTN_SEQ = BB.PTN_SEQ AND BB.DEL_YN = 'N' LEFT OUTER JOIN T_FILE_INF CC ON AA.MEMB_SEQ = CC.REF_SEQ AND CC.REF_CODE = 'FT_PROFILE' AND CC.DEL_YN = 'N'
AND AA.MEMB_SEQ = #{value , jdbcType=INTEGER} AND AA.USE_YN ='Y' AND AA.WTDR_YN = 'N'

